 22→export const uploadUserDataService = async(bio, name, image, userId, userEmail, username) =>{
 23→    if(!userId){
 24→        throw {status: 400, error: 'userId is undefined'};
 25→    }
 26→    if(!name || typeof name !== 'string' || name.length > 20){
 27→        throw {status: 400, error: 'name should be a string and not more than 20 characters'}
 28→    }
 29→    if(!bio || typeof bio !== 'string' || bio.length > 150){
 30→        throw {status: 400, error: 'bio should be a string and not more than 150 characters'}
 31→    }
 32→
 33→    // Validate username if provided
 34→    let validatedUsername = null;
 35→    if(username && typeof username === 'string'){
 36→        const trimmed = username.trim().toLowerCase();
 37→        if(trimmed.length < 3 || trimmed.length > 50){
 38→            throw {status: 400, error: 'username must be 3-50 characters'};
 39→        }
 40→        if(!/^[a-z0-9-]+$/.test(trimmed)){
 41→            throw {status: 400, error: 'username can only contain lowercase letters, numbers, and hyphens'};
 42→        }
 43→        // Check uniqueness
 44→        const {data: existing} = await supabase
 45→            .from('users')
 46→            .select('id')
 47→            .ilike('username', trimmed)
 48→            .limit(1);
 49→        if(existing && existing.length > 0){
 50→            throw {status: 409, error: 'username is already taken'};
 51→        }
 52→        validatedUsername = trimmed;
 53→    }
 54→
 55→    let publicUrl = null;
 56→    if(image){
 57→        const dataUrl = await imageUploader(image, userId, 'avatars');
 58→
 59→        publicUrl = dataUrl;
 60→    }
 61→
 62→    const data = {
 63→        bio: bio,
 64→        name: name,
 65→        id: userId,
 66→        user_email: userEmail || null,
 67→        image_url: publicUrl ? publicUrl : null
 68→    }
 69→
 70→    if(validatedUsername){
 71→        data.username = validatedUsername;
 72→    }
 73→
 74→    const {data: uploadData, error:errorUploadData} = await supabase
 75→    .from('users')
 76→    .insert([data])
 77→
 78→    if(errorUploadData){
 79→        console.error('supabase error:', errorUploadData.message);
 80→        throw {status:500, error:'supabase error while uploading data'}
 81→    }
 82→
 83→    return true;
 84→}
