322→export const updateJournalService = async(content, title, journalId, userId) => {
323→    if(!journalId){
324→        console.error('journalid is undefined');
325→        throw {status: 400, error: 'journalId is undefined'}
326→    }
327→
328→    if(!userId){
329→        console.error('userId is undefined')
330→        throw({status: 400, error: 'userId is undefined'})
331→    }
332→
333→    const {data: existingJournal, error: existingJournalError} = await supabase
334→    .from('journals')
335→    .select('id, user_id, content, title, post_type')
336→    .eq('id', journalId)
337→    .eq('user_id', userId)
338→    .maybeSingle();
339→
340→    if(existingJournalError){
341→        console.error('failed to fetch existing journal for update', existingJournalError.message);
342→        throw {status: 500, error: 'failed to fetch existing journal for update'};
343→    }
344→
345→    if(!existingJournal){
346→        console.error('journal not found for update');
347→        throw {status: 404, error: 'journal not found for update'};
348→    }
349→
350→    const resolvedTitle = typeof title === 'string' && title.trim() ? title.trim() : existingJournal.title;
351→    if(!resolvedTitle){
352→        console.error('title is undefined');
353→        throw {status: 400, error: 'title is undefined'};
354→    }
355→
356→    let resolvedContent = existingJournal.content;
357→    if(typeof content === 'string' && content.trim()){
358→        resolvedContent = content;
359→    }
360→
361→    if(!resolvedContent){
362→        console.error('text content is missing for text post update');
363→        throw {status: 400, error: 'text content is missing for text post update'};
364→    }
365→
366→    const parseData = parseTextContentSafely(resolvedContent);
367→    if(!parseData){
368→        console.error('failed to parse text content for update');
369→        throw {status: 400, error: 'failed to parse text content for update'};
370→    }
371→
372→    const embeddingBody = parseData.wholeText || '';
373→    const embeddings = await GenerateEmbeddings(resolvedTitle, embeddingBody);
374→
375→    if(!embeddings || !Array.isArray(embeddings) || embeddings.length === 0){
376→        console.error('failed to generate embeddings')
377→        throw {status: 400, error: 'failed to generate embeddings'};
378→    }
379→
380→    const journalData = {
381→        content: resolvedContent,
382→        title: resolvedTitle,
383→        post_type: POST_TYPE_TEXT,
384→        embeddings: embeddings
385→    }
386→
387→    const {data, error} = await supabase
388→    .from('journals')
389→    .update(journalData)
390→    .eq('id', journalId)
391→    .eq('user_id', userId)
392→
393→    if(error){
394→        console.error('supabase error while uploading content:', error.message);
395→        throw{status: 500, error: 'supabase error while uploading content'};
396→    }
397→
398→    return true;
399→}
