401→export const updateRepostCaptionService = async(journalId, userId, caption) => {
402→    if(!journalId){
403→        throw {status: 400, error: 'journalId is undefined'};
404→    }
405→    if(!userId){
406→        throw {status: 400, error: 'userId is undefined'};
407→    }
408→
409→    const trimmedCaption = typeof caption === 'string' ? caption.trim() : '';
410→    if(trimmedCaption.length > 280){
411→        throw {status: 400, error: 'caption must be 280 characters or less'};
412→    }
413→
414→    const {data: journal, error: fetchError} = await supabase
415→        .from('journals')
416→        .select('id, user_id, is_repost')
417→        .eq('id', journalId)
418→        .eq('user_id', userId)
419→        .maybeSingle();
420→
421→    if(fetchError){
422→        console.error('failed to fetch journal for repost caption update:', fetchError.message);
423→        throw {status: 500, error: 'failed to fetch journal'};
424→    }
425→
426→    if(!journal){
427→        throw {status: 404, error: 'journal not found'};
428→    }
429→
430→    if(!journal.is_repost){
431→        throw {status: 400, error: 'journal is not a repost'};
432→    }
433→
434→    const {error: updateError} = await supabase
435→        .from('journals')
436→        .update({repost_caption: trimmedCaption || null})
437→        .eq('id', journalId)
438→        .eq('user_id', userId);
439→
440→    if(updateError){
441→        console.error('supabase error while updating repost caption:', updateError.message);
442→        throw {status: 500, error: 'failed to update repost caption'};
443→    }
444→
445→    return true;
446→}
